// lib/data/customization/generic_grid/grid_filters.dart
import 'package:flutter/material.dart';
import 'grid_models.dart';
import 'grid_theme.dart';
import 'package:task_manager_flutter/utils/app_logger.dart';

class GridFiltersPanel extends StatelessWidget {
  final bool enableSearch;
  final TextEditingController searchCtrl;
  final Map<String, TextEditingController> filterCtrls;
  final List<FieldConfig> fieldConfigs;
  final VoidCallback onApply;
  final VoidCallback onClear;
  final VoidCallback onClose;

  const GridFiltersPanel({
    super.key,
    required this.enableSearch,
    required this.searchCtrl,
    required this.filterCtrls,
    required this.fieldConfigs,
    required this.onApply,
    required this.onClear,
    required this.onClose,
  });

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final tt = Theme.of(context).textTheme;
    return Card(
      margin: const EdgeInsets.all(16),
      child: Padding(
        padding: const EdgeInsets.all(20),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Row(children: [
            Icon(Icons.filter_alt, color: cs.primary),
            const SizedBox(width: 8),
            Text('Filtros e Busca', style: tt.titleMedium),
            const Spacer(),
            IconButton(
              onPressed: onClose,
              icon: Icon(Icons.close, color: cs.onSurface.withOpacity(0.6)),
            ),
          ]),
          const SizedBox(height: 12),
          if (enableSearch) ...[
            Text('Busca Global', style: tt.bodyMedium),
            const SizedBox(height: 8),
            TextField(
              controller: searchCtrl,
              decoration: InputDecoration(
                prefixIcon: const Icon(Icons.search),
                hintText: 'Buscar...',
                suffixIcon: searchCtrl.text.isNotEmpty
                    ? IconButton(
                        icon: const Icon(Icons.clear),
                        onPressed: () {
                          searchCtrl.clear();
                          L.d('[GridFilters] filtro global limpo');
                          onApply();
                        },
                      )
                    : null,
                filled: true,
                border: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(8),
                    borderSide: BorderSide.none),
              ),
              onChanged: (_) {
                L.d('[GridFilters] filtro global="${searchCtrl.text}"');
                onApply();
              },
            ),
            const SizedBox(height: 16),
          ],
          Text('Filtros por Campo', style: tt.bodyMedium),
          const SizedBox(height: 8),
          Wrap(
            spacing: 16,
            runSpacing: 12,
            children: fieldConfigs
                .where((c) => c.isFilterable)
                .map((c) => SizedBox(
                      width: 240,
                      child: TextField(
                        controller: filterCtrls[c.fieldName],
                        decoration: InputDecoration(
                          labelText: c.label,
                          prefixIcon:
                              Icon(c.icon ?? Icons.filter_list_alt, size: 18),
                          suffixIcon:
                              filterCtrls[c.fieldName]?.text.isNotEmpty == true
                                  ? IconButton(
                                      icon: const Icon(Icons.clear, size: 16),
                                      onPressed: () {
                                        filterCtrls[c.fieldName]?.clear();
                                        L.d('[GridFilters] filtro "${c.fieldName}" limpo');
                                        onApply();
                                      },
                                    )
                                  : null,
                          filled: true,
                          border: OutlineInputBorder(
                              borderRadius: BorderRadius.circular(8),
                              borderSide: BorderSide.none),
                        ),
                        onChanged: (_) {
                          L.d('[GridFilters] filtro "${c.fieldName}"="${filterCtrls[c.fieldName]?.text}"');
                          onApply();
                        },
                      ),
                    ))
                .toList(),
          ),
          const SizedBox(height: 16),
          Row(mainAxisAlignment: MainAxisAlignment.end, children: [
            FilledButton.tonal(
              onPressed: onClear,
              child: const Row(children: [
                Icon(Icons.clear_all, size: 18),
                SizedBox(width: 6),
                Text('Limpar')
              ]),
            ),
            const SizedBox(width: 12),
            FilledButton(
              onPressed: onApply,
              child: const Row(children: [
                Icon(Icons.check, size: 18),
                SizedBox(width: 6),
                Text('Aplicar')
              ]),
            ),
          ]),
        ]),
      ),
    );
  }
}
